<template>
  <div class="bg-white shadow rounded-md p-3">
    <TableView :current-page="currentPage" :page-size="pageSize" :all-pages-count="allPagesCount" @pagination-options-changed="paginationOptionsChanged">
      <template #filter>
        <div class="flex justify-between">
          <form class="grid grid-cols-2 md:grid-cols-3 gap-5">
            <div class="form_wrapper ">
              <input
                id="search"
                v-model="search" placeholder="Қидириш" class="base_input" name="search"
                type="text"
              >
            </div>
            <div class="form_wrapper">
              <select
                id="organId" v-model="organId" name="organId"
                class="base_input" @input="fetchJobDirectionListByOrganizationId"
              >
                <option value="" disabled selected>
                 Ташкилот бўйича танлаш
                </option>
                <option :value="null">
                  Барча
                </option>
                <option v-for="org in organizationList" :key="org.id" :value="org.id">
                  {{ org.name }}
                </option>
              </select>
            </div>
            <div class="form_wrapper ">
              <select
                id="directionId" v-model="directionId" name="directionId"
                class="base_input"
              >
                <option value="" disabled selected>
                 Йўналиш бўйича танлаш
                </option>
                <option :value="null">
                  Барча
                </option>
                <option v-for="dir in jobDirectionList" :key="dir.id" :value="dir.id">
                  {{ dir.name }}
                </option>
              </select>
            </div>
          </form>
          <button v-if="isSuperAdmin" class="bg-primary px-[6px] rounded-md text-white hover:opacity-60" @click="pushToCreateUsers">
            ishchi qo'shish
          </button>
        </div>
      </template>
      <template #table-content>
        <TableWorkers :table-body="workersList" @change-user-status="changeUserStatus" @delete-user="showModalDelete" />
      </template>
    </TableView>
    <ModalComponent ref="modal" modal-position="center">
      <template #slotBody>
        <h3 class="text-3xl text-center">
          Siz rostdan ham foydalanuvchini o'chirmoqchimisiz ?
        </h3>
        <div class="flex justify-center mt-7">
          <button class="px-3 py-1 rounded-md text-white bg-primary mx-auto " @click.prevent="deleteUser">
            Ҳа
          </button>
        </div>
      </template>
    </ModalComponent>
  </div>
</template>

<script setup>
import TableView from "../components/TableView";
import {computed, defineComponent, onMounted, ref, watch} from "vue";
import useOrganizationList from "../hooks/useOrganizationList";
import useJobDirectionsList from "../hooks/useJobDirectionsList";
import TableWorkers from "../components/TableWorkers";
import axios from "../plugins/axios";
import {useStore} from "vuex";
import ModalComponent from "../components/ModalComponent";
import {useRouter} from "vue-router";

const {organizationList} = useOrganizationList()
const {jobDirectionList,fetchJobDirectionListByOrganizationId} = useJobDirectionsList()

defineComponent({TableView,TableWorkers,ModalComponent})


const workersList = ref([])
const search = ref('')
const organId = ref('')
const directionId = ref('')
const store = useStore()
const deletableUserId = ref(null)
const modal = ref()
const router = useRouter()
const allPagesCount = ref(0)
const currentPage = ref(1)
const pageSize = ref(10)

onMounted(async()=>{
  await getWorkersList()
})

const isSuperAdmin = computed(()=>store.getters['getUserInfo'].role.name === 'SUPER_ADMIN')

function pushToCreateUsers(){
  router.push('/create_user')
}


async function getWorkersList(){
  const path = store.getters['getUserInfo'].role.name === 'SUPER_ADMIN' ? '/for-admin' : ''
  try {
   const resp =  (await axios.get('api/user'+path,{
     params:{
       organisationId:organId.value,
       directionId:directionId.value,
       search:search.value,
       size:pageSize.value,
       page:currentPage.value
     }
   })).data.data
   console.log(resp)
    allPagesCount.value  = resp.allPagesCount
    workersList.value = resp.content
    currentPage.value = resp.number + 1
    pageSize.value = resp.size
  } catch (e){
    await store.dispatch('errorHandler',e)
  }
}

async function changeUserStatus({id,status}){
  await axios.patch(`/api/user/status/${id}`,{
    status:status
  })
  await getWorkersList()
}

const showModalDelete = async(id)=>{
   deletableUserId.value = id
   modal.value.openModal()
  }

async function deleteUser(){
   try {
   const resp =  (await axios.delete(`/api/user/${deletableUserId.value}`)).data
   await store.dispatch('toast',{
     type:'success',
     message:resp.message
 })
   await getWorkersList()
   modal.value.closeModal()
   }catch (e) {
      await store.dispatch('errorHandler',e)
   }
  }


  function paginationOptionsChanged({page_size, page}){
  if(page_size){
    pageSize.value = +page_size
    getWorkersList() 
  }
  if(page){
    currentPage.value = +page
    getWorkersList() 
  }
}


watch([search,organId,directionId],async([s,o,d])=>{
  if(o === null){
    directionId.value = null
  }
    await getWorkersList()
})

</script>

