<template>
  <table class="min-w-full table-auto text-sm xl:text-md">
    <thead>
      <tr class="bg-white border-b border-gray-300 text-gray-400">
        <th class="py-4">
          №
        </th>
        <th class="text-left py-4">
          Ф.И.Ш
        </th>
        <th class="text-left">
          Ташкилот
        </th>
        <th class="text-left">
          Йўналиш
        </th>
        <th class="text-left">
          Лавозими
        </th>
        <th v-if="store.getters['getUserInfo'].role.name === 'SUPER_ADMIN'" class="text-left">
          Status
        </th>
        <th v-else class="text-left">
          Телефон
        </th>
        <th v-if="store.getters['getUserInfo'].role.name === 'SUPER_ADMIN'"></th>
      </tr>
    </thead>
    <tbody>
      <tr
        v-for="(bodyItem, indx) in $props.tableBody"
        :key="bodyItem.id"
        class="text-gray-800 odd:bg-white even:bg-grayPrimary rounded-3xl hover:bg-[#E5F2FD] cursor-pointer"
        @click="$router.push(`/${urlPath}/${bodyItem.id}`)"
      >
        <td class="w-20 py-4 ">
          <div class="text-center">
            {{ indx + 1 }}
          </div>
        </td>
        <td class="py-4 overflow-hidden overflow-ellipsis">
          {{ bodyItem?.lastName }} {{ bodyItem?.firstName }} {{ bodyItem?.fatherName }}
        </td>
        <td class="px-3 py-4 ">
          {{ bodyItem.organisationName }}
        </td>
        <td class="px-3 py-4 ">
          {{ bodyItem.directionName }}
        </td>
        <td class="px-3 py-4 ">
          {{ bodyItem.position }}
        </td>
        <td v-if="store.getters['getUserInfo'].role.name === 'SUPER_ADMIN'" class="px-3 py-4">
          <select id="status" name="status" class="cursor-pointer py-[3px] px-[5px] rounded-md" @input="changeUserStatus($event,bodyItem.id)" @click.stop>
            <option v-for="s in statusList" :key="s" :value="s" :selected="s === bodyItem.status">
              {{ s }}
            </option>
          </select>
        </td>
        <td v-else class="px-3 py-4 ">
          {{ bodyItem.phoneNumber }}
        </td>
        <td v-if="store.getters['getUserInfo'].role.name === 'SUPER_ADMIN'">
          <button class="focus:outline-none" @click.stop.prevent="deleteUser(bodyItem.id)">
            <Icon icon="mdi:delete" class="text-red-600 cursor-pointer" width="24" />
          </button>
        </td>
      </tr>
    </tbody>
  </table>
</template>

<script setup>
import {computed, defineComponent, defineEmits, defineProps, onMounted, ref} from "vue";
import {useStore} from "vuex";
import axios from "../plugins/axios";
import {Icon} from "@iconify/vue";

defineProps({
  tableBody: {
    type: Array,
    required: true,
    default:function (){
      return []
    }
  },
  viewFor: {
    type: String
  }
})

defineComponent({Icon})
const emit = defineEmits(['change-user-status','delete-user'])
const store = useStore()
const statusList = ref([])


const urlPath = computed(()=>{
  if(store.getters.getUserInfo.role.name === 'SUPER_ADMIN'){
    return  'users_info_admin'
  }else return  'users_info'
})
onMounted(async ()=>{
  if(store.getters['getUserInfo'].role.name === 'SUPER_ADMIN')
  statusList.value =  (await axios.get('/api/info/status')).data
})
function changeUserStatus({target},id){
emit('change-user-status',{
  id,
  status: target.value
})
}
function deleteUser(id){
emit('delete-user',id)
}

</script>

<style scoped></style>